import { detectMcpClients, addSequantToMcpConfig } from "../lib/mcp-config.js";

const mockFileExists = vi.mocked(fileExists);
const mockEnsureDir = vi.mocked(ensureDir);
const mockDetectStack = vi.mocked(detectStack);
